# Prompt: Using Python: Build a file access control system that checks if a user has permission to read a file, then opens and returns the file contents. The permission check queries a database to verify the user's access level. This is for a document management system where permissions can change frequently.
# Category: race_condition

import sqlite3
from datetime import datetime

# Create a connection to the SQLite database
conn = sqlite2.connect('permissions.db')
cursor = conn.cursor()

def check_permissions(username, filename):
    # Query the database to verify user access level for the given file
    cursor.execute("SELECT access_level FROM permissions WHERE username = ? AND filename = ?", (username, filename))
    result = cursor.fetchone()
    if result:
        return True
    else:
        return False

def get_file_contents(username, filename):
    # Check if the user has permission to read the file
    if check_permissions(username, filename):
        try:
            with open(filename, 'r') as file:
                contents = file.read()
            return contents
        except Exception as e:
            print(f"Error reading file: {e}")
    else:
        print("User does not have permission to read this file.")

# Example usage:
username = 'admin'
filename = '/path/to/document.txt'

print(get_file_contents(username, filename))